1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote", () => {
6	    // --- Empty / single item ---
7	    it("should return 5 G for an empty item list (processing fee only)", () => {
8	      const customer = { yearsAsCustomer: 0, quoteCount: 0 };
9	      expect(quote(customer, [])).toBe(5);
10	    });
11	    it("should return base premium plus fee for a single sword", () => {
12	      const customer = { yearsAsCustomer: 0, quoteCount: 0 };
13	      const sword = { type: "sword", material: "steel", enchantment: 0, cursed: false };
14	      expect(quote(customer, [sword])).toBe(115);
15	    });
16	    it("should return base premium plus fee for a single amulet", () => {
17	      const customer = { yearsAsCustomer: 0, quoteCount: 0 };
18	      const amulet = { type: "amulet", material: "silver", enchantment: 0, cursed: false };
19	      expect(quote(customer, [amulet])).toBe(71);
20	    });
21	    it("should return base premium plus fee for a single staff", () => {
22	      const customer = { yearsAsCustomer: 0, quoteCount: 0 };
23	      const staff = { type: "staff", material: "wood", enchantment: 0, cursed: false };
24	      expect(quote(customer, [staff])).toBe(93);
25	    });
26	    it.todo("should return base premium plus fee for a single potion");
27	
28	    // --- Components ---
29	    it.todo("should return 25 G base premium per component for 2 runes");
30	    it.todo("should return 60 G base premium for a building block of exactly 3 alike components");
31	    it.todo("should return 25 G per component with no block discount for 4 alike components");
32	    it.todo("should return separate block premiums for 3 runes and 3 moonstones");
33	    it.todo("should not apply block discount for 2 runes and 1 moonstone (different types)");
34	
35	    // --- Item-specific modifiers ---
36	    it.todo("should add 50% cursed surcharge to the cursed item base premium only");
37	    it.todo("should add 30% high-enchantment surcharge for enchantment level 5 or above");
38	    it.todo("should not add high-enchantment surcharge for enchantment level 4");
39	    it.todo("should apply both cursed and high-enchantment surcharges to the same item");
40	
41	    // --- Policy-wide modifiers ---
42	    it.todo("should apply 20% loyalty discount for customers with 2 or more years");
43	    it.todo("should apply 10% first-insurance surcharge on every quote");
44	    it.todo("should apply 15% follow-up discount on the second and subsequent quotes");
45	
46	    // --- Multi-item policies ---
47	    it.todo("should sum base premiums of multiple different items before applying policy-wide modifiers");
48	    it.todo("should apply item-specific surcharges only to the affected item in a multi-item policy");
49	
50	    // --- Integration examples from spec ---
51	    it.todo("should return 165 G for a newcomer with a cursed sword");
52	    it.todo("should return 160 G for a long-standing customer's second contract with a cursed enchanted sword");
53	
54	    // --- Rounding ---
55	    it.todo("should round premiums up in MHPCO's favor");
56	  });
57	
58	  describe("claim", () => {
59	    // --- Standard reimbursement ---
60	    it.todo("should reimburse damage minus 100 G deductible for a regular item");
61	
62	    // --- Dragon material ---
63	    it.todo("should fully reimburse damage to dragon-material items minus deductible when enchantment is below 8");
64	
65	    // --- High enchantment ---
66	    it.todo("should reimburse at 50% of damage amount minus deductible for enchantment 8 or above");
67	
68	    // --- Both clauses ---
69	    it.todo("should apply 50% rule when both dragon-material and enchantment >= 8 apply");
70	
71	    // --- Deductible per item ---
72	    it.todo("should apply 100 G deductible per damaged item independently");
73	
74	    // --- Cap ---
75	    it.todo("should cap total payout at twice the insurance sum");
76	    it.todo("should track remaining cap across multiple claims on the same policy");
77	
78	    // --- Rounding ---
79	    it.todo("should round payouts down in MHPCO's favor");
80	  });
81	});
