1	type Customer = {
2	  yearsAsCustomer: number;
3	  quoteCount: number;
4	};
5	
6	type Item = {
7	  type: string;
8	  material: string;
9	  enchantment: number;
10	  cursed: boolean;
11	};
12	
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	};
18	
19	const PROCESSING_FEE = 5;
20	const FIRST_INSURANCE_RATE = 0.1;
21	
22	export function quote(customer: Customer, items: Item[]): number {
23	  if (items.length === 0) return PROCESSING_FEE;
24	  const basePremium = BASE_PREMIUMS[items[0].type];
25	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
26	  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
27	}
28	
29	export function claim() {
30	  return undefined;
31	}
